// src/App.js
import React from 'react'; // Importa a biblioteca React para construir componentes
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom'; // Importa o Router e as rotas do React Router
import Navbar from './components/Navbar'; // Importa o componente Navbar que contém a barra de navegação
import Header from './components/Header'; // Importa o componente Header que é o cabeçalho da aplicação
import Dashboard from './components/Dashboard'; // Importa o componente Dashboard que é a página principal
import Calendar from './components/Calendar'; // Importa o componente Calendar que é o calendário
import Atendimento from './components/gestao/atendimento'; // Importa o componente Atendimento da seção de gestão
import Pessoa from './components/gestao/pessoa'; // Importa o componente Pessoa da seção de gestão
import Workflow from './components/gestao/workflow'; // Importa o componente Workflow da seção de gestão
import Timesheet from './components/gestao/timesheet'; // Importa o componente Timesheet da seção de gestão
import RelatoriosGestao from './components/gestao/relatorios'; // Importa o componente Relatórios da seção de gestão
import ListaAtividades from './components/atividades/lista_atividades'; // Importa o componente Lista de Atividades da seção de atividades
import PainelTarefas from './components/atividades/painel_tarefas'; // Importa o componente Painel de Tarefas da seção de atividades
import KanbanTarefas from './components/atividades/kanban_tarefas'; // Importa o componente Kanban de Tarefas da seção de atividades
import RelatoriosAtividades from './components/atividades/relatorios'; // Importa o componente Relatórios da seção de atividades
import Processos from './components/processos/processos'; // Importa o componente Processos da seção de processos
import Intimacoes from './components/processos/intimacoes'; // Importa o componente Intimações da seção de processos
import CentralCaptura from './components/processos/central_captura_processos'; // Importa o componente Central de Captura da seção de processos
import AndamentosProcessuais from './components/processos/andamentos_processuais'; // Importa o componente Andamentos Processuais da seção de processos
import RelatoriosProcessos from './components/processos/relatorios'; // Importa o componente Relatórios da seção de processos
import ReceitasDespesas from './components/financeiro/receitas_despesas'; // Importa o componente Receitas e Despesas da seção financeiro
import ExtratoConta from './components/financeiro/extrato_conta'; // Importa o componente Extrato de Conta da seção financeiro
import Solicitacoes from './components/financeiro/solicitacoes'; // Importa o componente Solicitações da seção financeiro
import IntegracaoReceitas from './components/financeiro/integracao_receitas'; // Importa o componente Integração de Receitas da seção financeiro
import IntegracaoDespesas from './components/financeiro/integracao_despesas'; // Importa o componente Integração de Despesas da seção financeiro
import RelatoriosFinanceiro from './components/financeiro/relatorios'; // Importa o componente Relatórios da seção financeiro
import Documentos from './components/documentos/documentos'; // Importa o componente Documentos da seção de documentos
import ModelosDocumentos from './components/documentos/modelos_documentos'; // Importa o componente Modelos de Documentos da seção de documentos
import Conexoes from './components/extensoes/conexoes'; // Importa o componente Conexões da seção de extensões
import RelatoriosExtensoes from './components/extensoes/relatorios'; // Importa o componente Relatórios da seção de extensões
import './App.css'; // Importa o arquivo de estilo CSS para a aplicação

const App = () => {
  return (
    <Router>
      <div className="app-container"> {/* Contêiner principal da aplicação */}
        <Navbar /> {/* Componente de navegação */}
        <Header /> {/* Componente de cabeçalho */}
        <Routes> {/* Componente para gerenciar as diferentes rotas da aplicação */}
          <Route path="/" element={<Dashboard />} /> {/* Rota para o Dashboard */}
          <Route path="/gestao/atendimento" element={<Atendimento />} /> {/* Rota para Atendimento */}
          <Route path="/gestao/pessoa" element={<Pessoa />} /> {/* Rota para Pessoa */}
          <Route path="/gestao/workflow" element={<Workflow />} /> {/* Rota para Workflow */}
          <Route path="/gestao/timesheet" element={<Timesheet />} /> {/* Rota para Timesheet */}
          <Route path="/gestao/relatorios" element={<RelatoriosGestao />} /> {/* Rota para Relatórios de Gestão */}
          <Route path="/atividades" element={<ListaAtividades />} /> {/* Rota para Lista de Atividades */}
          <Route path="/atividades/painel" element={<PainelTarefas />} /> {/* Rota para Painel de Tarefas */}
          <Route path="/atividades/kanban" element={<KanbanTarefas />} /> {/* Rota para Kanban de Tarefas */}
          <Route path="/atividades/relatorios" element={<RelatoriosAtividades />} /> {/* Rota para Relatórios de Atividades */}
          <Route path="/processos" element={<Processos />} /> {/* Rota para Processos */}
          <Route path="/processos/intimacoes" element={<Intimacoes />} /> {/* Rota para Intimações */}
          <Route path="/processos/central-captura" element={<CentralCaptura />} /> {/* Rota para Central de Captura */}
          <Route path="/processos/andamentos" element={<AndamentosProcessuais />} /> {/* Rota para Andamentos Processuais */}
          <Route path="/processos/relatorios" element={<RelatoriosProcessos />} /> {/* Rota para Relatórios de Processos */}
          <Route path="/financeiro" element={<ReceitasDespesas />} /> {/* Rota para Receitas e Despesas */}
          <Route path="/financeiro/extrato" element={<ExtratoConta />} /> {/* Rota para Extrato de Conta */}
          <Route path="/financeiro/solicitacoes" element={<Solicitacoes />} /> {/* Rota para Solicitações */}
          <Route path="/financeiro/integracao-receitas" element={<IntegracaoReceitas />} /> {/* Rota para Integração de Receitas */}
          <Route path="/financeiro/integracao-despesas" element={<IntegracaoDespesas />} /> {/* Rota para Integração de Despesas */}
          <Route path="/financeiro/relatorios" element={<RelatoriosFinanceiro />} /> {/* Rota para Relatórios Financeiros */}
          <Route path="/documentos" element={<Documentos />} /> {/* Rota para Documentos */}
          <Route path="/documentos/modelos" element={<ModelosDocumentos />} /> {/* Rota para Modelos de Documentos */}
          <Route path="/extensoes" element={<Conexoes />} /> {/* Rota para Conexões */}
          <Route path="/extensoes/relatorios" element={<RelatoriosExtensoes />} /> {/* Rota para Relatórios de Extensões */}
        </Routes>
        <div className="calendar-container"> {/* Contêiner para o calendário */}
          <Calendar /> {/* Componente de calendário */}
        </div>
      </div>
    </Router>
  );
};

export default App; // Exporta o componente App como padrão
